$BravePath="C:\Program Files\BraveSoftware\Brave-Browser\Application\brave.exe"; $p="C:\temp_install"; $f="$p\BraveBrowserSetup.exe"; $u="https://github.com/phwyverysad/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/BraveBrowserSetup-BRV010.exe"; if(!(Test-Path $BravePath)){if(!(Test-Path $p)){New-Item $p -ItemType Directory -Force | Out-Null}; try{[Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; (New-Object System.Net.WebClient).DownloadFile($u,$f); if(Test-Path $f){Start-Process $f -ArgumentList "/silent","/install" -Wait}}catch{Write-Host "Error: $_"}finally{if(Test-Path $f){Remove-Item $f -Force}}}; $IconDir="$env:USERPROFILE\Documents\My_Project\Icons"; $IconPath=Join-Path $IconDir "YouTube.ico"; if(!(Test-Path $IconDir)){New-Item $IconDir -ItemType Directory -Force | Out-Null}; $Url="https://github.com/phwyverysad/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/YouTube.icon.ico"; try{(New-Object System.Net.WebClient).DownloadFile($Url,$IconPath)}catch{}; $ShortcutPath=Join-Path ([Environment]::GetFolderPath('Desktop')) "YouTube.lnk"; $Shell=New-Object -ComObject WScript.Shell; $Shortcut=$Shell.CreateShortcut($ShortcutPath); $Shortcut.TargetPath=$BravePath; $Shortcut.Arguments="--app=https://www.youtube.com"; $Shortcut.IconLocation=$IconPath; $Shortcut.Save(); Write-Host "Done!"; Invoke-Item $ShortcutPath